fn fibonacci(n: Number) -> Number {
    if n <= 1 { return n }
    return fibonacci(n - 1) + fibonacci(n - 2)
}
fn fibonacci_sequence(limit: Number) -> [Number] {
    results = []
    for i in range(0, limit) {
        results = append(results, fibonacci(i))
    }
    return results
}
fn golden_ratio_appears(sequence: [Number]) -> Boolean {
    length = length(sequence)
    if length < 2 { return false }
    last = get(sequence, length - 1)
    second_last = get(sequence, length - 2)
    ratio = last / second_last
    return abs(ratio - 1.618) < 0.01
}
entry main(limit: Number) {
    sequence = fibonacci_sequence(limit)
    explanation = if golden_ratio_appears(sequence) {
        "The golden ratio appears in the sequence."
    } else {
        "The golden ratio does not appear in the sequence."
    }
    return join([to_text(sequence), " - ", explanation], "")
}

